<template><section><h1>门店验券</h1><p>美团、口碑、抖音券码验券与核销，当前为 Mock 通道。</p><div class="soft-card p-5"><div class="grid md:grid-cols-4 gap-3"><n-select v-model:value="form.channel" :options="channels"/><n-input v-model:value="form.code"/><n-input v-model:value="form.storeId"/><div class="flex gap-2"><n-button @click="verify">验券</n-button><n-button type="primary" @click="consume">核销</n-button></div></div><pre v-if="result">{{result}}</pre></div></section></template><script setup lang="ts">import{ref}from'vue';import{NSelect,NInput,NButton,useMessage}from'naive-ui';import{verifyVoucher,consumeVoucher}from'../api/modules';const msg=useMessage(),result=ref<any>();const channels=[{label:'美团',value:'MEITUAN'},{label:'口碑',value:'KOUBEI'},{label:'抖音',value:'DOUYIN'},{label:'Mock',value:'MOCK'}];const form=ref({channel:'MEITUAN',code:'MT88886666',storeId:'GZ-TIANHE',operatorId:'OP001'});async function verify(){result.value=(await verifyVoucher(form.value) as any).data;msg.success('验券完成')}async function consume(){result.value=(await consumeVoucher(form.value) as any).data;msg.success('核销完成')}</script>
